pgn_check_t __pgn_check_from_string(char *str, size_t *consumed)
{
    size_t cursor = 0;
    pgn_check_t check = PGN_CHECK_NONE;
    switch (str[cursor]) {
        case '+':
            while (str[cursor] == '+') {
                check++;
                cursor++;
            }
            assert(check <= 2);
            break;
        case '#':
            check = PGN_CHECK_MATE;
            cursor++;
            break;
    }
    *consumed += cursor;
    return check;
}
pgn_check_t pgn_check_from_string(char *str)
{
    size_t consumed = 0;
    return __pgn_check_from_string(str, &consumed);
}
